const toggle = document.querySelector('#theme-toggle');

// Apply saved preference on load
if (localStorage.getItem('theme') === 'dark') {
  document.body.classList.add('dark-mode');
  toggle.textContent = '☀️ Light mode';
}

toggle.addEventListener('click', () => {
  document.body.classList.toggle('dark-mode');
  const isDark = document.body.classList.contains('dark-mode');
  toggle.textContent = isDark ? '☀️ Light mode' : '🌙 Dark mode';
  localStorage.setItem('theme', isDark ? 'dark' : 'light');
});
```

This is a complete, real-world feature. The localStorage bonus makes the preference persist across page refreshes.

```js
const form = document.querySelector('#contact-form');
const feedback = document.querySelector('#feedback');

form.addEventListener('submit', (event) => {
  event.preventDefault();
  const name = document.querySelector('#name').value.trim();
  const email = document.querySelector('#email').value.trim();
  const message = document.querySelector('#message').value.trim();

  const errors = [];
  if (!name) errors.push('Name is required');
  if (!email.includes('@')) errors.push('Invalid email');
  if (message.length < 20) errors.push('Message too short (min 20 chars)');

  if (errors.length > 0) {
    feedback.textContent = errors.join(' | ');
    feedback.style.color = 'red';
    return;
  }

  feedback.textContent = "Message sent! We'll reply within 24 hours.";
  feedback.style.color = 'green';
  form.reset();
});
```
